    private val tokenLength = 32

    private var currentSessionId: String? = null
    private val activeTokens = mutableMapOf<String, TokenInfo>()

    data class TokenInfo(
        val token: String,
        val sessionId: String,
        val createdAt: Long,
        val expiresAt: Long,
        val purpose: TokenPurpose = TokenPurpose.API_REQUEST
    ) {
        fun isExpired(): Boolean = System.currentTimeMillis() > expiresAt
    }

    enum class TokenPurpose {
        API_REQUEST,
        FILE_UPLOAD,
        AUTHENTICATION,
        REFRESH
    }

    fun generateRandomString(length: Int = tokenLength): String {
        val sb = StringBuilder(length)
        for (i in 0 until length) {
            val index = secureRandom.nextInt(alphanumericChars.length)
            sb.append(alphanumericChars[index])
        }
        return sb.toString()
    }

