        currentSessionId = generateRandomString()
        return currentSessionId!!
    }

    fun getCurrentSessionId(): String? = currentSessionId

    fun isSessionActive(): Boolean = currentSessionId != null

    fun endSession() {
        currentSessionId?.let { sessionId ->
            activeTokens.entries.removeAll { it.value.sessionId == sessionId }
        }
        currentSessionId = null
    }

    fun generateTemporaryToken(
        expirationMillis: Long = 5 * 60 * 1000L,
        purpose: TokenPurpose = TokenPurpose.API_REQUEST
    ): TokenInfo? {
