        val info = activeTokens[token]
        if (info != null && info.isExpired()) {
            activeTokens.remove(token)
            return null
        }
        return info
    }

    fun getActiveTokenCount(): Int {
        cleanupExpiredTokens()
        return activeTokens.size
    }

    fun getActiveTokensForPurpose(purpose: TokenPurpose): List<TokenInfo> {
        cleanupExpiredTokens()
        return activeTokens.values.filter { it.purpose == purpose && it.sessionId == currentSessionId }
    }

    fun refreshToken(oldToken: String, newExpirationMillis: Long = 5 * 60 * 1000L): TokenInfo? {
