        activeTokens.remove(oldToken)
        return generateTemporaryToken(newExpirationMillis, oldTokenInfo.purpose)
    }

    fun invalidateAllTokens() {
        currentSessionId?.let { sessionId ->
            activeTokens.entries.removeAll { it.value.sessionId == sessionId }
